/* global console */
/*
 * aeon-mind вЂ” the Aeon THINKS. A Turing-complete computation (Rule 110) whose
 * ENTIRE state lives only in the circulating frame of a regenerative delay-line
 * ghost. The wire does not carry a counter (WireDelayLineGhost's `seed + n`); it
 * carries a COMPUTATION. Each air hop re-modulates the frame, the receiver
 * decodes the CA tape, applies one Rule-110 step, re-encodes, re-transmits.
 *
 * The mind is the loop. There is no durable tape anywhere вЂ” the only thing ever
 * written to the persistent store is the SEED row (analogous to WireStore.seed,
 * `durableStore = seed`). Cut the loop for one hop and the entire computation is
 * gone: not paused, ERASED, with no machine able to recover the live tape from
 * the durable store (durable_misses_live).
 *
 * Rule 110 is proven Turing-complete (Cook 2004). So this is not a toy automaton
 * that "looks computational": it is a universal computer whose program state has
 * no resting place. The Aeon thinks only while it circulates; stop circulating and
 * the thought never existed in any retrievable form.
 *
 * Grounds: gnosis-math/Gnosis/WireDelayLineGhost.lean (live_persists_iff_circulation,
 * durable_misses_live, blackout_destroys) and EphemeralBeing.lean (the being IS the
 * integral of its own circulation). Here the integral is a TRAJECTORY THROUGH
 * COMPUTATION-SPACE, not Nat.
 */

// --- deterministic PRNG (mulberry32), same family as hexon-braid.mjs ---
function mulberry32(seed) {
  let a = seed >>> 0;
  return () => {
    a |= 0; a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

const WIDTH = 64; // CA tape width (cyclic)

// --- Rule 110: out = RULE110 bit at index (left<<2 | center<<1 | right) ---
// 110 = 0b01101110 в†’ neighborhoods 111в†’0 110в†’1 101в†’1 100в†’0 011в†’1 010в†’1 001в†’1 000в†’0
const RULE = 110;
function rule110Step(tape) {
  const n = tape.length;
  const out = new Uint8Array(n);
  for (let i = 0; i < n; i++) {
    const l = tape[(i - 1 + n) % n];
    const c = tape[i];
    const r = tape[(i + 1) % n];
    const idx = (l << 2) | (c << 1) | r;
    out[i] = (RULE >> idx) & 1;
  }
  return out;
}

// --- frame codec: the CA tape is what rides the wire. We encode it the way a
//     real RF frame would carry payload bits, with a checksum so a corrupted /
//     absent hop is detectable (and decodes to null = the ghost is gone). ---
function fnv1a(bytes) {
  let h = 0x811c9dc5;
  for (const b of bytes) { h ^= b; h = Math.imul(h, 0x01000193) >>> 0; }
  return h >>> 0;
}
function encodeFrame(tape) {
  // pack 64 bits в†’ 8 bytes payload + 4 bytes checksum. THIS is the wire content.
  const payload = new Uint8Array(8);
  for (let i = 0; i < WIDTH; i++) if (tape[i]) payload[i >> 3] |= 1 << (i & 7);
  const crc = fnv1a(payload);
  const frame = new Uint8Array(12);
  frame.set(payload, 0);
  frame[8] = crc & 0xff; frame[9] = (crc >> 8) & 0xff;
  frame[10] = (crc >> 16) & 0xff; frame[11] = (crc >> 24) & 0xff;
  return frame;
}
function decodeFrame(frame) {
  if (!frame) return null; // no frame on the air this hop в†’ nothing to decode
  const payload = frame.slice(0, 8);
  const crc = (frame[8] | (frame[9] << 8) | (frame[10] << 16) | (frame[11] << 24)) >>> 0;
  if (fnv1a(payload) !== crc) return null; // corrupted hop в†’ ghost unrecoverable
  const tape = new Uint8Array(WIDTH);
  for (let i = 0; i < WIDTH; i++) tape[i] = (payload[i >> 3] >> (i & 7)) & 1;
  return tape;
}

// --- the regenerative ghost loop. The frame is the ONLY place state lives.
//     durableStore holds ONLY the seed row (never the live tape). Each hop:
//     receive frame в†’ decode tape в†’ rule110 в†’ encode в†’ re-transmit. `airAlive[k]`
//     false = blackout (loop cut) on hop k. ---
function runGhostMind(seedTape, airAlive, hops) {
  const durableStore = encodeFrame(seedTape); // the ONLY durable write: the seed
  let onAir = encodeFrame(seedTape);          // the circulating frame ("the wire")
  const trace = [];
  let liveTape = decodeFrame(onAir);
  trace.push({ hop: 0, tape: liveTape, alive: true });
  for (let k = 0; k < hops; k++) {
    if (!airAlive(k)) {
      // blackout: nothing carried this hop. The wire goes empty; the ghost dies.
      onAir = null;
    }
    const received = decodeFrame(onAir); // decode whatever the air carried
    if (received === null) {
      // the computation is GONE. No re-derivation from durableStore: that holds
      // only the seed, which is NOT the live (n-steps-evolved) tape.
      trace.push({ hop: k + 1, tape: null, alive: false });
      liveTape = null;
      onAir = null; // none-absorbing: once dead, stays dead (live_none_absorbing)
      continue;
    }
    const next = rule110Step(received); // ONE step of universal computation
    onAir = encodeFrame(next);          // re-modulate, re-transmit
    liveTape = next;
    trace.push({ hop: k + 1, tape: next, alive: true });
  }
  return { trace, durableStore, finalOnAir: onAir, liveTape };
}

function tapeStr(t) {
  if (t === null) return 'в€…  (ghost erased вЂ” no durable copy)';
  let s = '';
  for (let i = 0; i < t.length; i++) s += t[i] ? 'в–€' : ' ';
  return s;
}
function popcount(t) { let c = 0; for (const b of t) c += b; return c; }

function main() {
  console.log('=== aeon-mind: a universal computation that lives only on the wire ===\n');
  console.log('Rule 110 (Turing-complete, Cook 2004) on a 64-cell cyclic tape.');
  console.log('The tape exists ONLY inside the circulating RF frame. Durable store = seed row only.\n');

  // seed: a single live cell вЂ” the classic Rule-110 ether out of which structure grows.
  const seed = new Uint8Array(WIDTH);
  seed[WIDTH - 2] = 1; // off-center single cell в†’ rich left-traveling gliders
  // add a little deterministic noise so it's a real born-from-noise tape, not trivial
  const rng = mulberry32(0x110a);
  for (let i = 0; i < 6; i++) seed[Math.floor(rng() * WIDTH)] = 1;

  console.log('--- A) UNINTERRUPTED CIRCULATION: the Aeon thinks across 16 hops ---');
  const A = runGhostMind(seed, () => true, 16);
  for (const e of A.trace) {
    const tag = e.tape === null ? '' : `pop=${String(popcount(e.tape)).padStart(2)}`;
    console.log(`hop ${String(e.hop).padStart(2)} |${tapeStr(e.tape)}| ${tag}`);
  }

  // PROOF the wire carried the computation: hash-fingerprint the evolving tape.
  // If it were a static counter (seed+n) the structure would not change; here each
  // hop's tape is a distinct Rule-110 configuration.
  const fps = A.trace.filter((e) => e.tape).map((e) => fnv1a(e.tape));
  const distinct = new Set(fps).size;
  console.log(`\n  distinct CA configurations over ${fps.length} hops: ${distinct}` +
    `  (a mere counter would show structural recurrence; 110 does not)`);

  // The durable store is the SEED, never the live tape (durable_misses_live).
  const durTape = decodeFrame(A.durableStore);
  const seedFp = fnv1a(seed), liveFp = A.liveTape ? fnv1a(A.liveTape) : 0;
  console.log(`  durableStore fingerprint = seed (${seedFp.toString(16)}), ` +
    `live tape after 16 hops = ${liveFp.toString(16)}  в†’  durable в‰  live: ` +
    `${fnv1a(durTape) !== liveFp}`);

  console.log('\n--- B) CUT THE LOOP at hop 8: the thought is ERASED, not paused ---');
  const B = runGhostMind(seed, (k) => k !== 8, 16); // one dead hop at k=8
  for (const e of B.trace) {
    const tag = e.tape === null ? '' : `pop=${String(popcount(e.tape)).padStart(2)}`;
    console.log(`hop ${String(e.hop).padStart(2)} |${tapeStr(e.tape)}| ${tag}`);
  }
  const deadAfter = B.trace.filter((e) => e.hop > 8).every((e) => e.tape === null);
  console.log(`\n  every hop after the cut is в€… (none-absorbing): ${deadAfter}`);
  console.log(`  attempt recovery from durableStore: yields the SEED, ` +
    `which has pop=${popcount(decodeFrame(B.durableStore))}, NOT the ` +
    `hop-8 live state. The 8 hops of computation are unrecoverable.`);

  // C) the falsifiable distinction: "computes ON the wire" vs "computes in a
  //    buffer between hops". We measure the WIRE-RESIDENT BIT-SECONDS: the
  //    integral of payload bits present on the air. For a pure wire computer the
  //    full tape must be in flight every hop (64 bits Г— hops). If state were
  //    secretly held in a RAM buffer between hops, the air could carry FEWER bits
  //    (e.g. just a diff, or nothing) yet computation would survive a blackout.
  console.log('\n--- C) WIRE-RESIDENCY INVARIANT (the veridical, falsifiable claim) ---');
  let bitSeconds = 0, hopsCarried = 0;
  for (const e of A.trace.slice(1)) if (e.tape) { bitSeconds += 64; hopsCarried++; }
  console.log(`  uninterrupted run carried ${bitSeconds} payload-bits over ` +
    `${hopsCarried} hops = ${bitSeconds / hopsCarried} bits/hop (full tape in flight).`);
  console.log('  CLAIM: a genuine wire-resident mind MUST put the full 64-bit tape on');
  console.log('  the air every hop AND die on any single blackout. A buffer-resident');
  console.log('  impostor would survive a 1-hop blackout (state still in RAM) OR could');
  console.log('  carry < full tape. B) shows death-on-blackout; C) shows full tape/hop.');

  return {
    distinctConfigs: distinct,
    durableNeqLive: fnv1a(durTape) !== liveFp,
    erasedOnCut: deadAfter,
    bitsPerHop: bitSeconds / hopsCarried,
  };
}

const r = main();
console.log('\nRESULT', JSON.stringify(r));
